import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.Cr-Z7ngm.js";const h=JSON.parse('{"title":"哪些国家和地区可以开户","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"compliance-and-tax/eligible-countries.md","filePath":"zh-CN/compliance-and-tax/eligible-countries.md"}'),n={name:"compliance-and-tax/eligible-countries.md"};function o(l,a,c,s,d,p){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="哪些国家和地区可以开户" tabindex="-1">哪些国家和地区可以开户 <a class="header-anchor" href="#哪些国家和地区可以开户" aria-label="Permalink to &quot;哪些国家和地区可以开户&quot;">​</a></h1><p>FATF 成员国/地区定义及长桥开户支持的国家和跨境电汇限制条件。</p><h2 id="什么是-fatf" tabindex="-1">什么是 FATF <a class="header-anchor" href="#什么是-fatf" aria-label="Permalink to &quot;什么是 FATF&quot;">​</a></h2><p>FATF（Financial Action Task Force，金融行动特别工作组）是一个政府间机构，成立于 1989 年，由七国集团（G7）倡议设立。主要目标是制定并推广打击洗钱（Money Laundering）和恐怖融资（Terrorist Financing）的国际标准。</p><p>FATF 拥有 39 个成员，包括 37 个司法管辖区和 2 个区域组织（欧盟委员会和海湾合作委员会）。此外还有多个地区性组织（如亚太反洗钱组织 APG、欧洲反洗钱组织 MONEYVAL 等）作为准成员或观察员。</p><h2 id="与长桥开户的关系" tabindex="-1">与长桥开户的关系 <a class="header-anchor" href="#与长桥开户的关系" aria-label="Permalink to &quot;与长桥开户的关系&quot;">​</a></h2><p>目前长桥香港开户支持 FATF 成员国/地区。不支持使用美国和加拿大证件/信息开户，以及美国和加拿大居民申请开户。</p><p>跨境电汇入金仅支持 FATF 成员国家/地区的银行转账。请勿使用非 FATF 成员国家/地区银行卡转账至长桥账户，入金会被退回且退回手续费需自行承担。</p><h2 id="fatf-成员国-地区查询" tabindex="-1">FATF 成员国/地区查询 <a class="header-anchor" href="#fatf-成员国-地区查询" aria-label="Permalink to &quot;FATF 成员国/地区查询&quot;">​</a></h2><p><a href="https://www.fatf-gafi.org/en/countries/fatf.html" target="_blank" rel="noreferrer">FATF 成员国/地区完整名单</a></p><p>开户页面下拉列表中有的国家均支持开户。</p>',11)])])}const F=e(n,[["render",o]]);export{h as __pageData,F as default};
